      function CF_PAYMENT_AMOUNTFormula return Number is
v_calc_begin_date_varchar VARCHAR2(10);
v_calc_begin_date DATE;
V_AMOUNT NUMBER;
V_INS_REDUCTION NUMBER;
V_WORK_INS_CHILD_INCR NUMBER;

CURSOR cur_amount IS
SELECT WORKING_INS_REDUCTION, WORK_INS_CHILD_INCR
FROM PEN_ACCOUNT
WHERE ACCOUNT_NO =  :P_ACC_ACCOUNT_NO;


BEGIN

  OPEN cur_amount;
  FETCH cur_amount
  INTO V_INS_REDUCTION,
       V_WORK_INS_CHILD_INCR;
  CLOSE cur_amount;

	  v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
					 0,:p_form_id,'00001','00318','00420');
		IF v_calc_begin_date_varchar IS NOT NULL THEN
		   v_calc_begin_date := TO_DATE(v_calc_begin_date_varchar,'DD/MM/RRRR');
		END IF;


	V_AMOUNT := Penbat_Payments.Calc_Total_Scale_Raise_Back (NULL
																													 ,NULL
																													 ,v_calc_begin_date
																												 	 ,:P_ACC_START_DATE
																													 ,:P_PENSION_AMOUNT);
  
  RETURN (ROUND(V_AMOUNT,2)+ :P_PENSION_AMOUNT-NVL(V_INS_REDUCTION,0) + NVL(V_WORK_INS_CHILD_INCR,0)); 
  
  
END;

