IF V_BRANCH_CODE IS NULL	THEN		 
  V_BRANCH_CODE := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
			 0,:p_form_id,'00001','00069','00247');
END IF;  

IF V_BRANCH_CODE IS NULL	THEN		 
  V_BRANCH_CODE := GET_DANS_BRANCH_CODE(:P_ACC_ACCOUNT_NO,:CF_PRODUCT);
END IF;  

IF V_BRANCH_CODE IS NOT NULL THEN
       SELECT A.BRANCH_NAME
	   INTO V_BRANCH_NAME
	   FROM COM_ORG_BRANCHES A
	   WHERE A.BRANCH_CODE = V_BRANCH_CODE;
ELSE 
      V_BRANCH_NAME := ' ';
END IF;

RETURN V_BRANCH_NAME;
END;

      FUNCTION CF_PRESUMED_WAGEFormula RETURN NUMBER IS

v_amount NUMBER;

CURSOR cur_presumed IS 
SELECT A.PRESUMED_WAGES
FROM COM_CURRENT_PRESUMED_WAGES A
WHERE A.PREWAG_INSURANCE_CLASS = :INSURANCE_CLASS
AND A.FROM_DAILY_WAGES <= ROUND(:NOTICE_TOTAL_SALARY_TEAM/:NOTICE_TOTAL_DAYS_TEAM,2)
AND (A.TO_DAILY_WAGES >= ROUND(:NOTICE_TOTAL_SALARY_TEAM/:NOTICE_TOTAL_DAYS_TEAM,2)
		 OR :INSURANCE_CLASS = 28)
AND A.EFFECTIVENESS_START_DATE <= TO_DATE('31'||'12'||:PERIOD_YEAR_TO_TEAM,'DD/MM/RRRR') 
ORDER BY A.EFFECTIVENESS_START_DATE DESC;


BEGIN
  
--INSERT INTO ERROR_DEBUG VALUES ('KSXX',':PERIOD_YEAR_TO_TEAM',:PERIOD_YEAR_TO_TEAM);
--INSERT INTO ERROR_DEBUG VALUES ('KSXX',':INSURANCE_CLASS',:INSURANCE_CLASS);
--INSERT INTO ERROR_DEBUG VALUES ('KSXX',':NOTICE_TOTAL_SALARY_TEAM',:NOTICE_TOTAL_SALARY_TEAM);
--INSERT INTO ERROR_DEBUG VALUES ('KSXX',':NOTICE_TOTAL_DAYS_TEAM',:NOTICE_TOTAL_DAYS_TEAM);
--COMMIT;
  
  IF NVL(:NOTICE_TOTAL_DAYS_TEAM,0)!= 0 THEN 
	  OPEN cur_presumed;
	  FETCH cur_presumed
	  INTO v_amount;
	  CLOSE cur_presumed;
  ELSE 
  	v_amount:=NULL;
  END IF;

  RETURN v_amount;
END;

